import os, base64
base = "C:/Users/Григорий/code/AppMonitor"

files = {}

files["core/database.py"] = ""
files["main.py"] = ""
files["core/monitor.py"] = ""
files["core/notifier.py"] = ""
files["core/reporter.py"] = ""
files["core/autostart.py"] = ""
files["core/scheduler.py"] = ""
files["ui/main_window.py"] = ""
files["requirements.txt"] = "UHlRdDU+PTUuMTUKcHl3aW4zMj49MzA2CnNjaGVkdWxlPj0xLjIK"
files["core/__init__.py"] = ""
files["ui/__init__.py"] = ""

for path, b64 in files.items():
    if b64:
        content = base64.b64decode(b64).decode('utf-8')
    else:
        content = ''
    full = os.path.join(base, path)
    os.makedirs(os.path.dirname(full), exist_ok=True)
    with open(full, 'w', encoding='utf-8') as f:
        f.write(content)
    print(f'Written: {path}')
print('All files deployed!')
